const input = $json.body ?? $json;
const required = ['name', 'email', 'company', 'message'];
const missingFields = required.filter((field) => {
  const value = input[field];
  return value === undefined || value === null || String(value).trim() === '';
});

return [
  {
    json: {
      ...input,
      _validation: {
        isValid: missingFields.length === 0,
        missingFields
      }
    }
  }
];

const trimText = (value) => typeof value === 'string' ? value.trim() : value;

const normalized = {
  name: trimText($json.name),
  email: trimText($json.email)?.toLowerCase(),
  company: trimText($json.company),
  message: trimText($json.message),
  source: trimText($json.source || 'webhook'),
  received_at: new Date().toISOString()
};

return [{ json: normalized }];

const text = `${$json.message || ''}`.toLowerCase();
let leadScore = 45;

if (text.includes('automation')) leadScore += 20;
if (text.includes('crm')) leadScore += 15;
if (text.includes('urgent') || text.includes('asap')) leadScore += 10;
if (text.length > 120) leadScore += 5;

leadScore = Math.max(0, Math.min(100, leadScore));

let leadCategory = 'cold';
let priority = 'low';

if (leadScore >= 80) {
  leadCategory = 'high-fit';
  priority = 'high';
} else if (leadScore >= 60) {
  leadCategory = 'qualified';
  priority = 'medium';
}

const summary = `${$json.name} from ${$json.company} submitted a ${leadCategory} lead with score ${leadScore}.`;

return [{
  json: {
    ...$json,
    lead_score: leadScore,
    lead_category: leadCategory,
    priority,
    summary
  }
}];

const leadId = `LD-${Date.now()}`;

return [{
  json: {
    lead_id: leadId,
    status: 'qualified',
    lead: {
      name: $json.name,
      email: $json.email,
      company: $json.company,
      message: $json.message,
      source: $json.source,
      received_at: $json.received_at
    },
    ai_output: {
      lead_score: $json.lead_score,
      lead_category: $json.lead_category,
      priority: $json.priority,
      summary: $json.summary
    },
    storage_payload: {
      table: 'leads',
      operation: 'insert',
      record_preview: {
        company: $json.company,
        email: $json.email,
        score: $json.lead_score,
        priority: $json.priority
      }
    }
  }
}];

const message = `New qualified lead: ${$json.lead.name} from ${$json.lead.company}, priority: ${$json.ai_output.priority}`;

return [{
  json: {
    ...$json,
    internal_notification: {
      channel: 'internal-alerts',
      message
    }
  }
}];

return [{
  json: {
    status: 'error',
    error_type: 'validation_error',
    message: 'Required lead fields are missing.',
    missing_fields: $json._validation?.missingFields || []
  }
}];
